import{_ as r,o as a,c as n,ag as o}from"./chunks/framework.NIzFHKo_.js";const _=JSON.parse('{"title":"ADR-0009: Backup Server Control Plane & Internet Access Layer","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0009_backup_server_control_plane_and_public_edge_pattern.md","filePath":"10_core/10_governance/50_decisions/adr-0009_backup_server_control_plane_and_public_edge_pattern.md"}'),t={name:"10_core/10_governance/50_decisions/adr-0009_backup_server_control_plane_and_public_edge_pattern.md"};function i(l,e,s,c,d,u){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-0009-backup-server-control-plane-internet-access-layer" tabindex="-1">ADR-0009: Backup Server Control Plane &amp; Internet Access Layer <a class="header-anchor" href="#adr-0009-backup-server-control-plane-internet-access-layer" aria-label="Permalink to &quot;ADR-0009: Backup Server Control Plane &amp; Internet Access Layer&quot;">​</a></h1><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>QiOS requires a pattern for deploying user-controlled, internet-accessible backup servers on secondary hardware. These nodes provide infrastructure services like local AI runtimes, data storage, and public application hosting. Historically, exposing such services often involved insecure port forwarding or mixing administrative and public traffic.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>QiOS adopts a dual-path access model for self-hosted infrastructure nodes:</p><ol><li><strong>Private Control Plane</strong>: Administrative access (SSH, Docker Management, DB Admin) must occur exclusively over a secure private network overlay (e.g., Tailscale/WireGuard).</li><li><strong>Public Edge Exposure</strong>: Intentionally public services (portals, webhooks) must be exposed via an outbound tunnel (e.g., Cloudflare Tunnels) and routed through a local reverse proxy.</li></ol><p>The node shall be organized into four conceptual runtime zones:</p><ul><li><strong>Zone A (Private Admin)</strong>: No public routing.</li><li><strong>Zone B (Public App)</strong>: Governed tunnel/proxy path.</li><li><strong>Zone C (Data Services)</strong>: Internal-only state services.</li><li><strong>Zone D (AI Execution)</strong>: Internal-only model runtimes.</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>This approach:</p><ul><li>Minimizes the attack surface for administrative tools.</li><li>Eliminates the need for inbound port forwarding on local networks.</li><li>Separates internal data and AI concerns from public application exposure.</li><li>Aligns with the QiOS doctrine of modular, governed device nodes.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Increased security for self-hosted infrastructure.</li><li>Requirement for a private network overlay and tunnel provider.</li><li>Clearer operational boundaries for service deployment on infrastructure nodes.</li></ul>',13)])])}const h=r(t,[["render",i]]);export{_ as __pageData,h as default};
